const crypto = require('crypto');
const express = require('express');
const app = express();
const cookieParser = require('cookie-parser');

app.use(express.json());
app.use(cookieParser());

// Function to hash passwords
function hashPassword(password) {
    return crypto.createHash('sha256').update(password).digest('hex');
}

// Function to set a long-lived cookie
function setLongLivedCookie(res, name, value, days) {
    const date = new Date();
    date.setTime(date.getTime() + (days * 24 * 60 * 60 * 1000));
    res.cookie(name, value, { expires: date, httpOnly: true });
}

// Function to get a cookie
function getCookie(req, name) {
    return req.cookies[name];
}

// Route for login
app.post('/login', (req, res) => {
    const { username, password } = req.body;
    const hashedPassword = hashPassword(password);

    // Simulate database check
    if (username === 'admin' && hashedPassword === 'expected_hashed_password') {
        if (req.body.rememberMe) {
            setLongLivedCookie(res, 'username', username, 30);
            setLongLivedCookie(res, 'passwordHash', hashedPassword, 30);
        }
        res.send('Login successful');
    } else {
        res.status(401).send('Invalid credentials');
    }
});

// Route for auto-login
app.get('/auto-login', (req, res) => {
    const username = getCookie(req, 'username');
    const passwordHash = getCookie(req, 'passwordHash');

    if (username && passwordHash) {
        // Simulate database check
        if (username === 'admin' && passwordHash === 'expected_hashed_password') {
            res.send('Auto-login successful');
        } else {
            res.status(401).send('Invalid credentials');
        }
    } else {
        res.send('No saved login data');
    }
});

